import React, { Component } from 'react';
import { View, Text, Image, TouchableOpacity, Linking, StyleSheet, Platform } from 'react-native';
import { formatTime, getUserName } from '../utils/format';
import { emojiFromName, replaceEmojisInText } from '../utils/emoji';

var AVATAR_COLORS = [
  '#E8912D', '#2BAC76', '#CD2553', '#1264A3',
  '#9B59B6', '#E74C3C', '#00BCD4', '#4A154B',
  '#3498DB', '#E67E22', '#1ABC9C', '#8E44AD',
];

function hashCode(str) {
  var hash = 0;
  for (var i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash);
}

function getAvatarColor(userId) {
  return AVATAR_COLORS[hashCode(userId || '') % AVATAR_COLORS.length];
}

function getProfileImage(userId, usersMap) {
  var u = usersMap[userId];
  if (u && u.profile) {
    return u.profile.image_72 || u.profile.image_48 || null;
  }
  return null;
}

function getFileProxyUrl(url, token) {
  if (Platform.OS === 'web' && url && token) {
    return '/slack-file?url=' + encodeURIComponent(url) + '&token=' + encodeURIComponent(token);
  }
  return url;
}

function isImageFile(file) {
  if (file.mimetype && file.mimetype.indexOf('image/') === 0) return true;
  var name = (file.name || file.title || '').toLowerCase();
  return name.match(/\.(png|jpg|jpeg|gif|webp|bmp|svg)$/) !== null;
}

function getImageUrl(file) {
  return file.url_private || file.url_private_download || file.thumb_480 || file.thumb_360 || file.thumb_160 || null;
}

function openUrl(url) {
  if (Platform.OS === 'web') {
    window.open(url, '_blank');
  } else {
    Linking.openURL(url).catch(function () {});
  }
}

export default class MessageItem extends Component {
  constructor(props) {
    super(props);
    this.state = {
      failedImages: {},
    };
  }

  onImageError(index) {
    var self = this;
    this.setState(function (prev) {
      var failed = Object.assign({}, prev.failedImages);
      failed[index] = true;
      return { failedImages: failed };
    });
  }

  renderMessageText(text) {
    if (!text) return null;
    var converted = replaceEmojisInText(text);
    return <Text style={styles.text}>{converted}</Text>;
  }

  renderReaction(r, i) {
    var emoji = emojiFromName(r.name);
    return (
      <View key={i} style={styles.reactionBadge}>
        {emoji ? (
          <Text style={styles.reactionEmoji}>{emoji}</Text>
        ) : (
          <Text style={styles.reactionShortcode}>:{r.name}:</Text>
        )}
        <Text style={styles.reactionCount}>{r.count}</Text>
      </View>
    );
  }

  renderImageFile(f, i, token) {
    var imgUrl = getImageUrl(f);
    if (!imgUrl || this.state.failedImages[i]) {
      return this.renderFileCard(f, i);
    }
    var src = getFileProxyUrl(imgUrl, token);
    var w = f.original_w || 360;
    var h = f.original_h || 240;
    var maxW = 360;
    var maxH = 300;
    if (w > maxW) { h = Math.round(h * (maxW / w)); w = maxW; }
    if (h > maxH) { w = Math.round(w * (maxH / h)); h = maxH; }
    if (w < 100) w = 200;
    if (h < 60) h = 140;

    var self = this;
    var permalink = f.permalink || f.permalink_public || imgUrl;

    return (
      <TouchableOpacity
        key={i}
        style={styles.imageWrapper}
        activeOpacity={0.8}
        onPress={function () { openUrl(permalink); }}
      >
        <Image
          source={{ uri: src }}
          style={{ width: w, height: h, borderRadius: 6 }}
          resizeMode="cover"
          onError={function () { self.onImageError(i); }}
        />
        {f.name ? (
          <Text style={styles.imageCaption} numberOfLines={1}>{f.name}</Text>
        ) : null}
      </TouchableOpacity>
    );
  }

  renderFileCard(f, i) {
    var permalink = f.permalink || f.permalink_public || f.url_private || '';
    var ext = (f.filetype || '').toUpperCase();
    var sizeKB = f.size ? Math.round(f.size / 1024) : null;

    return (
      <TouchableOpacity
        key={i}
        style={styles.fileCard}
        activeOpacity={0.7}
        onPress={function () { if (permalink) openUrl(permalink); }}
      >
        <View style={styles.fileIcon}>
          <Text style={styles.fileIconText}>{ext ? ext.substring(0, 3) : 'F'}</Text>
        </View>
        <View style={styles.fileInfo}>
          <Text style={styles.fileName} numberOfLines={1}>{f.name || f.title || 'attachment'}</Text>
          <Text style={styles.fileMeta}>
            {ext}{sizeKB ? (ext ? ' · ' : '') + sizeKB + ' KB' : ''}
          </Text>
        </View>
      </TouchableOpacity>
    );
  }

  render() {
    var { message, usersMap, currentUserId, onLongPress, onThreadPress, token } = this.props;

    if (message.subtype === 'channel_join' || message.subtype === 'channel_leave' ||
        message.subtype === 'group_join' || message.subtype === 'group_leave') {
      return (
        <View style={styles.systemMsg}>
          <View style={styles.systemLine} />
          <Text style={styles.systemText}>{replaceEmojisInText(message.text)}</Text>
          <View style={styles.systemLine} />
        </View>
      );
    }

    var userName = message.username || getUserName(message.user, usersMap);
    var time = formatTime(message.ts);
    var edited = message.edited ? ' (edited)' : '';
    var threadCount = message.reply_count || 0;
    var reactions = message.reactions || [];
    var files = message.files || [];
    var profileImg = getProfileImage(message.user, usersMap);
    var initial = (userName || '?').charAt(0).toUpperCase();
    var avatarBg = getAvatarColor(message.user);
    var self = this;

    return (
      <TouchableOpacity
        style={styles.container}
        onLongPress={function () { onLongPress && onLongPress(message); }}
        activeOpacity={0.8}
      >
        <View style={styles.avatarCol}>
          {profileImg ? (
            <Image source={{ uri: profileImg }} style={styles.avatar} />
          ) : (
            <View style={[styles.avatar, styles.avatarFallback, { backgroundColor: avatarBg }]}>
              <Text style={styles.avatarInitial}>{initial}</Text>
            </View>
          )}
        </View>
        <View style={styles.contentCol}>
          <View style={styles.headerRow}>
            <Text style={styles.userName}>{userName}</Text>
            <Text style={styles.time}>{time}{edited}</Text>
          </View>

          {this.renderMessageText(message.text)}

          {files.length > 0 ? (
            <View style={styles.filesContainer}>
              {files.map(function (f, i) {
                if (isImageFile(f)) {
                  return self.renderImageFile(f, i, token);
                }
                return self.renderFileCard(f, i);
              })}
            </View>
          ) : null}

          {reactions.length > 0 ? (
            <View style={styles.reactionsRow}>
              {reactions.map(function (r, i) {
                return self.renderReaction(r, i);
              })}
            </View>
          ) : null}

          {threadCount > 0 ? (
            <TouchableOpacity
              style={styles.threadLink}
              onPress={function () { onThreadPress && onThreadPress(message); }}
            >
              <View style={styles.threadBar} />
              <Text style={styles.threadText}>
                {threadCount} {threadCount === 1 ? 'reply' : 'replies'}
              </Text>
              <Text style={styles.threadArrow}>  View thread</Text>
            </TouchableOpacity>
          ) : null}
        </View>
      </TouchableOpacity>
    );
  }
}

